#include<bits/stdc++.h>
using namespace std;
long long a[2000010],s[2000010],n;
multiset<long long> st;
int main()
{
    long long q;
    scanf("%*d%lld",&q);
    long long cnt=0,id=1;
    while(q--)
    {
        long long op;
        scanf("%lld",&op);
        if(op==1)
        {
            long long x;
            scanf("%lld",&x);
            a[++n]=x;
            s[n]=s[n-1]+x;
            st.insert(x);
        }
        else if(op==2)
        {
            long long x;
            scanf("%lld",&x);
            cnt+=x;
            while(s[id]<=cnt&&id<=n)
            {
                st.erase(st.find(a[id]));
                id++;
            }
        }
        else if(op==3)
        {
            long long x;
            scanf("%lld",&x);
            x+=cnt;
            long long pos=lower_bound(s+1,s+1+n,x)-s-1;
            printf("%lld\n",x-s[pos]);
        }
        else
        {
            printf("%lld\n",(*st.rbegin()));
        }
    }
    return 0;
}
